import{_ as e,o as a,c as o,a0 as n}from"./chunks/framework.jwovEGr5.js";const s="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR4nGMAAQAABQABDQottAAAAABJRU5ErkJggg==",p=JSON.parse(`{"title":"\\"You don't have access\\" — What It Means","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/access-denied.md","filePath":"getting-started/access-denied.md"}`),r={name:"getting-started/access-denied.md"};function i(d,t,l,h,u,c){return a(),o("div",null,[...t[0]||(t[0]=[n('<h1 id="you-don-t-have-access-—-what-it-means" tabindex="-1">&quot;You don&#39;t have access&quot; — What It Means <a class="header-anchor" href="#you-don-t-have-access-—-what-it-means" aria-label="Permalink to &quot;&quot;You don&#39;t have access&quot; — What It Means&quot;">​</a></h1><p>Sooner or later you&#39;ll try to open a page or press a button and the app will tell you that you don&#39;t have access. This is normal and, almost always, working as intended. This guide explains why it happens and what to do.</p><p><img src="'+s+'" alt="Access denied page"></p><h2 id="why-it-happens" tabindex="-1">Why it happens <a class="header-anchor" href="#why-it-happens" aria-label="Permalink to &quot;Why it happens&quot;">​</a></h2><p>Every page and action in the app is tied to a <a href="./../roles/overview.html">role</a> and a <a href="./glossary.html#scope">scope</a>. If your role doesn&#39;t include a particular ability — or the thing you&#39;re trying to reach is outside your kingdom or alliance — the app stops you rather than showing or changing data you shouldn&#39;t touch.</p><p>This is a feature, not a fault. It keeps one alliance from editing another&#39;s data, and stops accidental changes to platform‑wide settings.</p><h2 id="the-common-situations" tabindex="-1">The common situations <a class="header-anchor" href="#the-common-situations" aria-label="Permalink to &quot;The common situations&quot;">​</a></h2><table tabindex="0"><thead><tr><th>What you see</th><th>What it usually means</th><th>What to do</th></tr></thead><tbody><tr><td>A menu item is simply <strong>not there</strong></td><td>Your role doesn&#39;t include that area</td><td>Nothing&#39;s wrong; you don&#39;t need it for your role</td></tr><tr><td>An <strong>&quot;access denied&quot; / forbidden</strong> page after clicking a link</td><td>You reached a page your role can&#39;t open (e.g. an old bookmark)</td><td>Go back to your <a href="./dashboard-tour.html">dashboard</a></td></tr><tr><td><strong>&quot;You cannot delete your own account&quot;</strong></td><td>A safety rule is protecting you</td><td>Ask another admin if the account really must go — see <a href="./../roles/protection-rules.html">Safety Rules</a></td></tr><tr><td><strong>&quot;At least one active supreme admin must remain&quot;</strong></td><td>You&#39;re trying to remove the last top‑level admin</td><td>This is blocked on purpose; appoint another first</td></tr><tr><td><strong>&quot;You can only delete users that you created&quot;</strong></td><td>A King can only remove accounts they made</td><td>Ask the Supreme Admin to handle it</td></tr><tr><td>A &quot;scope&quot; style refusal (kingdom/alliance)</td><td>You tried to view or change something outside your area</td><td>Confirm your <a href="./navigating.html#the-context-banner--knowing-where-you-are">context</a>; you likely don&#39;t have rights there</td></tr><tr><td>Something is <strong>locked</strong> and won&#39;t save</td><td>The event instance is locked (usually because it ended a while ago)</td><td>You can request it be unlocked — covered in the events section</td></tr><tr><td>A <strong>quota / suspension</strong> message</td><td>Your kingdom or alliance hit a limit or was paused</td><td>See the subscriptions section; a King or Supreme Admin can help</td></tr></tbody></table><p>Several of these are <strong>safety rules</strong> — deliberate guardrails. The full list is in <a href="./../roles/protection-rules.html">Safety Rules You&#39;ll Run Into</a>.</p><h2 id="is-this-a-bug" tabindex="-1">Is this a bug? <a class="header-anchor" href="#is-this-a-bug" aria-label="Permalink to &quot;Is this a bug?&quot;">​</a></h2><p>Usually not. Before assuming something&#39;s broken:</p><ol><li><strong>Check your context banner</strong> — are you in the right kingdom/alliance?</li><li><strong>Check your role</strong> — the <a href="./../roles/overview.html">roles overview</a> lists what each role can do.</li><li><strong>Try from your dashboard</strong> — a stale link or bookmark can point at a page you can&#39;t open.</li></ol><h2 id="who-to-ask" tabindex="-1">Who to ask <a class="header-anchor" href="#who-to-ask" aria-label="Permalink to &quot;Who to ask&quot;">​</a></h2><ul><li><strong>Need access you don&#39;t have?</strong> Ask the person one level up: an Alliance Player asks a Leader; a Leader asks their King; a King asks the Supreme Admin.</li><li><strong>Think your role is wrong?</strong> Only admins can change roles. Ask your King or Supreme Admin to review your <a href="./glossary.html#assignment">assignment</a>.</li><li><strong>Blocked by a safety rule?</strong> Read <a href="./../roles/protection-rules.html">Safety Rules You&#39;ll Run Into</a> first — most of the time the block is correct and there&#39;s a proper way around it.</li></ul>',14)])])}const m=e(r,[["render",i]]);export{p as __pageData,m as default};
